EFS, type NodeTypeName, type EwWorkflowGraph } from './graph-types';\n\nconst props = defineProps<{\n  graph: EwWorkflowGraph | null;\n}>();\n\nconst emit = defineEmits<{\n  (event: 'add-node', type: NodeTypeName): void;\n}>();\n\nconst menuOpen = ref(false);\nconst nodeTypes = Object.values(NODE_TYPE_DEFS);\n\n/** 统计图中的管线链数（= trigger 节点数） */\nconst chainCount = computed(() =>\n  props.graph?.nodes.filter(n => n.type === 'trigger').length ?? 0,\n);\n\nfunction addNode(type: NodeTypeName) {\n  emit('add-node', type);\n  menuOpen.value = false;\n}\n</script>\n\n<style scoped>\n.ew-graph-toolbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 8px 16px;\n  background: rgba(15, 18, 30, 0.9);\n  backdrop-filter: blur(12px);\n}\n\n.ew-graph-toolbar__left {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n}\n\n.ew-graph-toolbar__title {\n  font-size: 0.95rem;\n  font-weight: 600;\n  color: rgba(255, 255, 255, 0.8);\n  white-space: nowrap;\n}\n\n.ew-graph-toolbar__badge {\n  font-size: 0.72rem;\n  color: rgba(255, 255, 255, 0.45);\n  background: rgba(255, 255, 255, 0.06);\n  padding: 2px 8px;\n  border-radius: 10px;\n  border: 1px solid rgba(255, 255, 255, 0.08);\n}\n\n.ew-graph-toolbar__right {\n  display: flex;\n  gap: 8px;\n}\n\n.ew-graph-toolbar__add-menu {\n  position: relative;\n}\n\n.ew-graph-toolbar__btn {\n  padding: 6px 14px;\n  border-radius: 6px;\n  border: 1px solid rgba(255, 255, 255, 0.12);\n  background: rgba(255, 255, 255, 0.06);\n  color: rgba(255, 255, 255, 0.8);\n  font-size: 0.85rem;\n  cursor: pointer;\n  transition: all 0.15s;\n}\n\n.ew-graph-toolbar__btn:hover {\n  background: rgba(255, 255, 255, 0.12);\n}\n\n.ew-graph-toolbar__dropdown {\n  position: absolute;\n  right: 0;\n  top: calc(100% + 4px);\n  min-width: 180px;\n  background: rgba(20, 24, 36, 0.95);\n  backdrop-filter: blur(16px);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 8px;\n  padding: 4px;\n  z-index: 100;\n  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);\n}\n\n.ew-graph-toolbar__dropdown-item {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  width: 100%;\n  padding: 8px 12px;\n  border: none;\n  border-radius: 6px;\n  background: transparent;\n  color: rgba(255, 255, 255, 0.75);\n  font-size: 0.85rem;\n  cursor: pointer;\n  transition: background 0.12s;\n}\n\n.ew-graph-toolbar__dropdown-item:hover {\n  background: rgba(255, 255, 255, 0.08);\n}\n\n.ew-graph-toolbar__dot {\n  width: 8px;\n  height: 8px;\n  border-radius: 50%;\n  flex-shrink: 0;\n}\n</style>\n"],"sourceRoot":""}]);
